# Limit query depth and complexity to prevent abuse
# We set a max depth for introspection and queries
MAX_QUERY_DEPTH = 10


def check_query_depth(document, max_depth=MAX_QUERY_DEPTH):
    """
    Check the depth of a GraphQL query to prevent deeply nested abuse queries.
    Returns True if within limits, raises an error otherwise.
    """
    from graphql.language import ast as graphql_ast

    def _get_depth(node, current_depth=0):
        if current_depth > max_depth:
            raise Exception(
                f"Query depth {current_depth} exceeds maximum allowed depth of {max_depth}."
            )
        max_found = current_depth
        if hasattr(node, "selection_set") and node.selection_set:
            for selection in node.selection_set.selections:
                child_depth = _get_depth(selection, current_depth + 1)
                max_found = max(max_found, child_depth)
        return max_found

    for definition in document.definitions:
        if hasattr(definition, "selection_set") and definition.selection_set:
            _get_depth(definition)

    return True


class DepthLimitingMiddleware:
    """Middleware to limit query depth."""

    def resolve(self, next, root, info, **args):
        # Only check on the root resolver
        if info.path is not None:
            path_list = []
            current = info.path
            while current:
                path_list.append(current.key)
                current = current.prev
            if len(path_list) > MAX_QUERY_DEPTH:
                raise Exception(f"Query depth exceeds maximum allowed depth of {MAX_QUERY_DEPTH}.")
        return next(root, info, **args)


schema = graphene.Schema(
    query=Query,
    mutation=Mutations,
    description="User Management API with secure profile updates.",
)


class MockContext:
    """Mock context simulating an authenticated request."""

    def __init__(self, user_id=None):
        self.user_id = user_id


def execute_query(query_string, context=None, variables=None):
    """Execute a GraphQL query with optional context and variables."""
    result = schema.execute(
        query_string,
        context=context,
        variables=variables,
        middleware=[DepthLimitingMiddleware()],
    )
    response = {}
    if result.data:
        response["data"] = result.data
    if result.errors:
        response["errors"] = [str(e) for e in result.errors]
    return response


